#pragma once

#include <cstdint>
#include <string_view>

// Detect whether the standard library provides <source_location>.
//
// CMake / Bazel may target C++20 but ship a libcxx / libc++abi whose libstdc++
// / MSVC STL does not yet implement std::source_location (common on OpenHarmony,
// older clang/LLVM, some embedded toolchains).
//
// When the feature is unavailable we provide a zero-cost, standards-safe
// fallback that is transparent to callers.  We deliberately do *not* extend
// namespace std with user-defined types (that is undefined behaviour per
// [namespace.std]/1).  All internal call sites use mbgl::source_location
// (or the macro alias below) which resolves to the right type.

#if __has_include(<source_location>)
#define MBGL_SOURCE_LOCATION_HAS_SOURCE_LOCATION 1

// The standard header must be included so that std::source_location exists.
#include <source_location>

namespace mbgl {

// Forward-declare the standard type so that the macro below always works.
using source_location = std::source_location;

} // namespace mbgl

#else // __has_include(<source_location>)
#define MBGL_SOURCE_LOCATION_HAS_SOURCE_LOCATION 0

namespace mbgl {

// Standards-safe fallback: a value-type with the same interface as
// std::source_location, implemented with compiler builtins and C preprocessor
// macros.  This type is *not* placed inside namespace std ([namespace.std]/1).
class source_location {
public:
    source_location()                                                          = default;
    constexpr source_location(source_location&&) noexcept                      = default;
    constexpr auto& operator=(source_location&&) noexcept                      = default;
    constexpr source_location(const source_location&) noexcept                 = default;
    constexpr auto& operator=(const source_location&) noexcept                 = default;
    ~source_location()                                                         = default;

    // The caller-facing factory that captures the call site.
    //
    // On compilers that expose __builtin_* variants we use them because they
    // are slightly more reliable than the __FILE__/__LINE__ macros (which
    // can be affected by #line directives and macros).  On compilers that
    // lack the builtins we fall back to the preprocessor macros, which is
    // still useful for diagnostics.
    constexpr static source_location current(const char* file         = __FILE__,
                                             const char* function     = __builtin_FUNCTION(),
                                             unsigned     line        = __builtin_LINE(),
                                             unsigned     column      = 0) noexcept
        {
            return source_location{file, function, line, column};
        }

    [[nodiscard]] constexpr unsigned line() const noexcept { return line_; }
    [[nodiscard]] constexpr unsigned column() const noexcept { return column_; }
    [[nodiscard]] constexpr const char* file_name() const noexcept { return file_; }
    [[nodiscard]] constexpr std::string_view function_name() const noexcept {
        return std::string_view{function_, function_len_};
    }

private:
    constexpr source_location(const char* file, const char* function, unsigned line, unsigned column) noexcept
        : file_(file), function_(function), function_len_(_strlen(function)), line_(line), column_(column) {}

    const char* file_;
    const char* function_;
    // Store the length so we do not store an extra pointer.
    uint32_t function_len_;
    unsigned line_;
    unsigned column_;

    constexpr static uint32_t _strlen(const char* s) noexcept {
        uint32_t n = 0;
        while (*s++) ++n;
        return n;
    }
};

// Convenience factory in case the caller prefers a free function.
inline source_location location(const char* file         = __FILE__,
                                const char* function     = __builtin_FUNCTION(),
                                unsigned     line        = __builtin_LINE(),
                                unsigned     column      = 0) noexcept {
    return source_location::current(file, function, line, column);
}

} // namespace mbgl

#endif // __has_include(<source_location>)

// Macro alias so that code expecting a __STDCPP__-style name still compiles.
// After this point `::source_location` and `mbgl::source_location` are
// interchangeable in guard blocks.
namespace mbgl {
using source_location =
#if __has_include(<source_location>)
    std::source_location;
#else
    source_location;
#endif
} // namespace mbgl

