#ifndef MLN_SYMBOL_GUARDS
#define MLN_SYMBOL_GUARDS 1
#endif

#if MLN_SYMBOL_GUARDS
#define SYM_GUARD_VALUE(N) std::uint64_t check##N = checkVal;
#else
#define SYM_GUARD_VALUE(N)
#endif

// Capture the call-site for diagnostics.  With <source_location> available
// we get the real std::source_location::current().  In the fallback path the
// macro expands the preprocessor macros into mbgl::source_location::current()
// which accepts the same parameters.
#if MLN_SYMBOL_GUARDS
#define SYM_GUARD_LOC mbgl::source_location::current(__FILE__, __FUNCTION__, __LINE__)
#else
#define SYM_GUARD_LOC
#endif

namespace mbgl {

class Anchor;
class IndexedSubfeature;

struct ShapedTextOrientations {
    Shaping horizontal;
    Shaping vertical;
    // The following are used with variable text placement on.
    Shaping& right = horizontal;
    Shaping center;
    Shaping left;
    bool singleLine = false;
};

enum class SymbolContent : uint8_t {
