#pragma once

// Provide std::source_location when available, otherwise supply a
// standards-safe fallback implemented inside the mbgl namespace.
//
// The C++ standard ([namespace.std]/1) forbids adding user-defined
// declarations to namespace std except for carefully-specified
// specialisations.  We therefore never define a type named
// source_location in namespace std ourselves; we simply alias or
// forward-declare when the toolchain already provides it.

#include <cstdint>
#include <string_view>

#if __has_include(<source_location>)
#define MBGL_SOURCE_LOCATION_HAS_SOURCE_LOCATION 1
#include <source_location>

namespace mbgl {

/// When the standard library ships std::source_location we provide
/// a thin alias with the same qualified name so call-sites written
/// as `mbgl::source_location` work regardless of toolchain.
using source_location = std::source_location;

} // namespace mbgl

#else // __has_include(<source_location>)

namespace mbgl {

/// standards-safe fallback source_location
class source_location {
public:
    source_location()                                                          = default;
    constexpr source_location(source_location&&) noexcept                      = default;
    constexpr auto& operator=(source_location&&) noexcept                      = default;
    constexpr source_location(const source_location&) noexcept                 = default;
    constexpr auto& operator=(const source_location&) noexcept                 = default;
    ~source_location()                                                         = default;

    /// Capture the current call site using compiler builtins + preprocessor.
    /// The parameters exist so that a caller-macro can pass its own values
    /// when necessary (the macro in symbol_instance.hpp still uses this).
    [[nodiscard]] constexpr static source_location
        current(const char* file         = __FILE__,
                const char* function     = __builtin_FUNCTION(),
                unsigned     line        = __builtin_LINE(),
                unsigned     column      = 0) noexcept {
        return source_location{file, function, line, column};
    }

    [[nodiscard]] constexpr unsigned line() const noexcept { return line_; }
    [[nodiscard]] constexpr unsigned column() const noexcept { return column_; }
    [[nodiscard]] constexpr const char* file_name() const noexcept { return file_; }
    [[nodiscard]] constexpr std::string_view function_name() const noexcept {
        return std::string_view{function_, function_len_};
    }

private:
    constexpr source_location(const char* file, const char* function,
                              unsigned line, unsigned column) noexcept
        : file_(file), function_(function), function_len_(string_len_(function)),
          line_(line), column_(column) {}

    const char* file_;
    const char* function_;
    uint32_t function_len_;
    unsigned line_;
    unsigned column_;

    // __builtin_FUNCTION() may return a mangled name; __FUNCTION__
    // usually returns a demangled name on GCC/clang, so we keep both
    // options available via the current() parameterisation.
    constexpr static uint32_t string_len_(const char* s) noexcept {
        uint32_t n = 0;
        while (*s++) ++n;
        return n;
    }
};

} // namespace mbgl

#endif // __has_include(<source_location>)

